// ============================================================
// JobService v2 ? Validation (IDENTIQUE ? v1)
// ============================================================

const inputs = $input.all();

const VALID_ACTIONS = [
  'CREATE_JOB',
  'GET_JOB',
  'UPDATE_JOB',
  'FIND_BY_REQUEST_ID',
  'LIST_BY_STATUS'
];

function normAction(a) {
  return (a || '').toString().trim().toUpperCase();
}

function assert(cond, msg) {
  if (!cond) throw new Error(msg);
}

return inputs.map((item, idx) => {
  const input = item.json || {};
  const action = normAction(input.action);

  assert(action, `JobService ? Champ obligatoire manquant: action (item #${idx})`);
  assert(input.tenant_id !== undefined && input.tenant_id !== null && String(input.tenant_id).trim() !== '',
    `JobService ? Champ obligatoire manquant: tenant_id (item #${idx})`);
  assert(VALID_ACTIONS.includes(action),
    `JobService ? Action inconnue: '${action}' (item #${idx}). Valides: ${VALID_ACTIONS.join(', ')}`);

  if (action === 'CREATE_JOB') {
    const required = ['request_id', 'source_agent', 'channel_name', 'credential_ref', 'diffusion_type'];
    const missing = required.filter(f => !input[f]);
    assert(missing.length === 0,
      `JobService CREATE_JOB ? Champs obligatoires manquants (item #${idx}): ${missing.join(', ')}`);
  }

  if (action === 'GET_JOB') {
    assert(input.job_id, `JobService GET_JOB ? Champ obligatoire manquant: job_id (item #${idx})`);
  }

  if (action === 'UPDATE_JOB') {
    assert(input.job_id, `JobService UPDATE_JOB ? Champ obligatoire manquant: job_id (item #${idx})`);
    assert(input.fields && typeof input.fields === 'object',
      `JobService UPDATE_JOB ? Champ obligatoire manquant ou invalide: fields (objet) (item #${idx})`);
  }

  if (action === 'FIND_BY_REQUEST_ID') {
    assert(input.request_id, `JobService FIND_BY_REQUEST_ID ? Champ obligatoire manquant: request_id (item #${idx})`);
  }

  if (action === 'LIST_BY_STATUS') {
    assert(input.status, `JobService LIST_BY_STATUS ? Champ obligatoire manquant: status (item #${idx})`);
  }

  return { json: { ...input, action, __req_idx: idx }, pairedItem: { item: idx } };
});

// ============================================================
// BRANCHE CREATE_JOB v2 — Préparer l'INSERT PostgreSQL
// ============================================================
// CHANGEMENTS vs v1 :
//   - payload reste en objet JS (PostgreSQL JSONB l'accepte tel quel)
//   - Pas besoin de JSON.stringify le payload
//   - last_error aussi en JSONB (pas string)
//   - updated_at géré par trigger (mais on l'envoie quand même
//     pour cohérence avec created_at)
// ============================================================

const inputs = $input.all();
const now = new Date();

function genJobId() {
  const year = now.getFullYear();
  const hex = Array.from({ length: 6 }, () =>
    Math.floor(Math.random() * 16).toString(16).toUpperCase()
  ).join('');
  return `JOB-${year}-${hex}`;
}

return inputs.map((item, idx) => {
  const input = item.json || {};
  const job_id = genJobId();
  const timestamp = now.toISOString();

  let status = 'RECEIVED';
  if (input.scheduled_at) {
    const scheduledDate = new Date(input.scheduled_at);
    if (scheduledDate > new Date()) status = 'SCHEDULED';
  }

  // Payload en objet (pas string) — JSONB PostgreSQL
  let payload = input.payload || {};
  if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch(e) { payload = {}; }
  }

  return {
    json: {
      job_id,
      request_id: input.request_id,
      batch_id: input.batch_id || '',
      diffusion_id: input.diffusion_id || null,
      source_agent: input.source_agent,
      tenant_id: input.tenant_id,
      client_id: input.client_id || null,
      campaign_id: input.campaign_id || null,
      channel_name: input.channel_name,
      credential_ref: input.credential_ref,
      diffusion_type: input.diffusion_type,
      funnel_stage: input.funnel_stage || null,
      scheduled_at: input.scheduled_at || null,
      timezone: input.timezone || 'Africa/Casablanca',
      budget_amount: input.budget_amount || null,
      budget_currency: input.budget_currency || null,
      payload: JSON.stringify(payload),
      status,
      retry_count: 0,
      retry_max: input.retry_max || 3,
      timestamp,
      // Conserver le contexte pour la réponse
      __req_idx: input.__req_idx ?? idx,
      __original_input: input,
    },
    pairedItem: { item: item.pairedItem?.item ?? idx }
  };
});

// ============================================================
// Réponse CREATE_JOB v2 (PostgreSQL)
// ============================================================
// CHANGEMENTS vs v1 :
//   - Plus de airtable_record_id
//   - Unicité garantie par la BDD (UNIQUE constraint sur job_id
//     et sur request_id+channel_name) — si doublon, PG lève une
//     erreur, pas besoin de FIND_BY_REQUEST_ID en amont
// ============================================================

const records = $input.all();
const allReq = $items('Valider entrée & action').map((it, idx) => ({
  __req_idx: idx,
  ...it.json
}));
const reqs = allReq.filter(r => r.action === 'CREATE_JOB');

return reqs.map((rq, idx) => {
  const row = records[idx]?.json || {};

  return {
    json: {
      ...rq,
      success: true,
      action: 'CREATE_JOB',
      job_id: row.job_id || 'UNKNOWN',
      status: row.status || 'UNKNOWN',
      created_at: row.created_at || new Date().toISOString(),
    },
    pairedItem: { item: rq.__req_idx }
  };
});

// ============================================================
// Réponse GET_JOB v2 (PostgreSQL)
// ============================================================
// SIMPLIFICATION vs v1 :
//   - Plus de rec.fields vs rec (PG retourne plat)
//   - payload déjà en objet (JSONB, pas besoin de JSON.parse)
//   - last_error aussi en objet JSONB
// ============================================================

const items = $input.all();
const allReq = $items('Valider entrée & action').map(i => i.json);
const reqs = allReq.filter(r => r.action === 'GET_JOB');

return reqs.map((rq, subIdx) => {
  const row = items[subIdx]?.json;

  if (!row || !row.job_id) {
    return {
      json: {
        success: false,
        action: 'GET_JOB',
        error_code: 'JOB_NOT_FOUND',
        error_message: 'Aucun DiffusionJob trouvé avec ce job_id',
      },
      pairedItem: { item: rq.__req_idx },
    };
  }

  return {
    json: {
      success: true,
      action: 'GET_JOB',
      job: {
        job_id: row.job_id,
        request_id: row.request_id || '',
        batch_id: row.batch_id || '',
        diffusion_id: row.diffusion_id || null,
        source_agent: row.source_agent || '',
        tenant_id: row.tenant_id ?? null,
        client_id: row.client_id || null,
        campaign_id: row.campaign_id || null,
        channel_name: row.channel_name || '',
        credential_ref: row.credential_ref || '',
        diffusion_type: row.diffusion_type || '',
        funnel_stage: row.funnel_stage || '',
        scheduled_at: row.scheduled_at || null,
        timezone: row.timezone || '',
        budget_amount: row.budget_amount || null,
        budget_currency: row.budget_currency || '',
        payload: row.payload || {},
        status: row.status || '',
        retry_count: row.retry_count || 0,
        retry_max: row.retry_max || 3,
        platform_post_id: row.platform_post_id || '',
        last_error: row.last_error || null,
        created_at: row.created_at || '',
        updated_at: row.updated_at || '',
      },
    },
    pairedItem: { item: rq.__req_idx },
  };
});

// ============================================================
// BRANCHE UPDATE_JOB v2 — Construire l'UPDATE SQL dynamique
// ============================================================
// SIMPLIFICATION MAJEURE vs v1 :
//   v1 : Préparer → FIND → Build Payload → UPDATE → Réponse (5 nœuds)
//   v2 : Build SQL dynamique → PostgreSQL UPDATE → Réponse (3 nœuds)
//
// On construit dynamiquement le SET clause en fonction des
// champs fournis dans `fields`. Seuls les champs présents
// sont mis à jour (partial update).
//
// BONUS :
//   - updated_at est géré par le trigger PostgreSQL
//   - payload et last_error sont convertis en JSONB
//   - Requête paramétrisée (anti-injection)
// ============================================================

const inputs = $input.all();

return inputs.map((item, idx) => {
  const input = item.json || {};
  const fields = { ...(input.fields || {}) };
  const job_id = input.job_id;

  // Liste des colonnes modifiables
  const ALLOWED_FIELDS = [
    'status', 'payload', 'last_error', 'platform_post_id',
    'retry_count', 'retry_max', 'scheduled_at', 'budget_amount',
    'budget_currency', 'funnel_stage'
  ];

  // Construire SET dynamiquement
  const setClauses = [];
  const values = [];
  let paramIdx = 1;

  for (const [key, value] of Object.entries(fields)) {
    if (!ALLOWED_FIELDS.includes(key)) continue;

    let castSuffix = '';
    let val = value;

    // Conversions de type pour PostgreSQL
    if (key === 'payload' || key === 'last_error') {
      val = typeof value === 'object' ? JSON.stringify(value) : value;
      castSuffix = '::jsonb';
    } else if (key === 'retry_count' || key === 'retry_max') {
      castSuffix = '::smallint';
    } else if (key === 'scheduled_at') {
      castSuffix = '::timestamptz';
    } else if (key === 'budget_amount') {
      castSuffix = '::numeric';
    }

    setClauses.push(`${key} = $${paramIdx}${castSuffix}`);
    values.push(val);
    paramIdx++;
  }

  if (setClauses.length === 0) {
    throw new Error(`JobService UPDATE_JOB — aucun champ modifiable dans fields (item #${idx})`);
  }

  // job_id est le dernier paramètre pour le WHERE
  values.push(job_id);
  values.push(input.tenant_id);
  const whereParam = `$${paramIdx}`;
  const tenantParam = `$${paramIdx + 1}`;

  const query = `UPDATE diffusion.jobs SET ${setClauses.join(', ')} WHERE job_id = ${whereParam} AND tenant_id = ${tenantParam}::bigint RETURNING job_id, status, updated_at;`;

  return {
    json: {
      _query: query,
      _values: values,
      _job_id: job_id,
      _updated_fields: Object.keys(fields).filter(k => ALLOWED_FIELDS.includes(k)),
      __req_idx: input.__req_idx ?? idx,
    },
    pairedItem: item.pairedItem ?? { item: idx }
  };
});

// ============================================================
// Réponse UPDATE_JOB v2 (PostgreSQL)
// ============================================================

const results = $input.all();
const buildItems = $items('Construire UPDATE dynamique');

return results.map((item, idx) => {
  const row = item.json || {};
  const meta = buildItems[idx]?.json || {};

  if (!row.job_id) {
    return {
      json: {
        success: false,
        action: 'UPDATE_JOB',
        job_id: meta._job_id || 'UNKNOWN',
        error_code: 'JOB_NOT_FOUND',
        error_message: `job_id '${meta._job_id}' introuvable — UPDATE a retourné 0 lignes`,
      },
      pairedItem: { item: meta.__req_idx ?? idx },
    };
  }

  return {
    json: {
      success: true,
      action: 'UPDATE_JOB',
      job_id: row.job_id,
      status: row.status,
      updated_at: row.updated_at,
      updated_fields: meta._updated_fields || [],
    },
    pairedItem: { item: meta.__req_idx ?? idx },
  };
});

// ============================================================
// Réponse FIND_BY_REQUEST_ID v2 (PostgreSQL)
// ============================================================
// CHANGEMENT vs v1 :
//   - PostgreSQL utilise l'index uq_jobs_request_channel → O(log n)
//   - Airtable faisait un scan complet de la table
// ============================================================

const items = $input.all();
const allReq = $items('Valider entrée & action').map((it, idx) => ({
  __req_idx: idx,
  ...it.json
}));
const reqs = allReq.filter(r => r.action === 'FIND_BY_REQUEST_ID');

return reqs.map((rq, subIdx) => {
  // PostgreSQL peut retourner plusieurs lignes (1 par canal)
  // On considère qu'il existe un doublon si au moins 1 ligne
  const rows = items.filter(i => i.json?.request_id === rq.request_id);

  if (rows.length === 0 || !rows[0].json?.job_id) {
    return {
      json: {
        ...rq,
        success: true,
        action: 'FIND_BY_REQUEST_ID',
        exists: false,
        request_id: rq.request_id,
      },
      pairedItem: { item: rq.__req_idx },
    };
  }

  const first = rows[0].json;

  return {
    json: {
      ...rq,
      success: true,
      action: 'FIND_BY_REQUEST_ID',
      exists: true,
      request_id: first.request_id,
      existing_job_id: first.job_id || '',
      existing_status: first.status || '',
      existing_channel: first.channel_name || '',
    },
    pairedItem: { item: rq.__req_idx },
  };
});

// ============================================================
// Réponse LIST_BY_STATUS v2 (PostgreSQL)
// ============================================================
// BONUS vs v1 :
//   - LIMIT 200 pour éviter de surcharger la mémoire
//   - ORDER BY created_at DESC (les plus récents en premier)
//   - idx_jobs_status rend cette requête O(log n)
// ============================================================

const items = $input.all();
const allReq = $items('Valider entrée & action').map(i => i.json);
const reqs = allReq.filter(r => r.action === 'LIST_BY_STATUS');

return reqs.map((rq, subIdx) => {
  const jobs = items
    .map(i => i.json)
    .filter(row => row && row.job_id)
    .map(row => ({
      job_id: row.job_id,
      request_id: row.request_id || '',
      channel_name: row.channel_name || '',
      status: row.status || '',
      scheduled_at: row.scheduled_at || null,
      created_at: row.created_at || '',
    }));

  return {
    json: {
      success: true,
      action: 'LIST_BY_STATUS',
      status_filter: rq.status,
      count: jobs.length,
      jobs,
    },
    pairedItem: { item: rq.__req_idx },
  };
});
